function globalSearch() {
    var q = document.getElementById('stockSearch').value.trim().toLowerCase();
    var box = document.getElementById('searchResults');
    if (!q) { box.style.display = 'none'; return; }
    var matches = SEARCH_INDEX.filter(function(s) {
        return s.c.toLowerCase().indexOf(q) !== -1 || s.n.toLowerCase().indexOf(q) !== -1;
    }).slice(0, 20);
    if (matches.length === 0) {
        box.innerHTML = '<div style="padding:12px;color:#718096;text-align:center;">找不到符合的個股</div>';
        box.style.display = 'block';
        return;
    }
    var prefix = window.ROOT_PATH || '';
    var html = '';
    matches.forEach(function(s) {
        html += '<a href="' + prefix + s.d + '/' + s.h + '">';
        html += '<span class="sr-code">' + s.c + '</span>';
        html += '<span class="sr-name">' + s.n + '</span>';
        html += '<span class="sr-list">' + s.l + '</span>';
        html += '</a>';
    });
    box.innerHTML = html;
    box.style.display = 'block';
}
document.addEventListener('click', function(e) {
    var box = document.getElementById('searchResults');
    if (box && !e.target.closest('.search-box')) box.style.display = 'none';
});
